#include <bits/stdc++.h>
using namespace std;
bool f(int q,int w){
    if(q>w)  return true;
    else  return false;
}
int n,m,t,a[1010][1010];
int x[1010],y[1010],sum;
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            cin>>a[i][j];
        }
    }
    cin>>t;
    for(int i=0;i<t;i++){
        int x1,x2,y1,y2;
        cin>>x1>>y1>>x2>>y2;
        swap(a[x1][y1],a[x2][y2]);
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            if(f(a[i][j],a[i][j+1]) && f(a[i][j],a[i][j-1]) && f(a[i][j],a[i+1][j]) && f(a[i][j],a[i-1][j])){
                sum++;
            }
        }
    }
    cout<<sum<<endl;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            if(f(a[i][j],a[i][j+1]) && f(a[i][j],a[i][j-1]) && f(a[i][j],a[i+1][j]) && f(a[i][j],a[i-1][j])){
                cout<<i<<' '<<j<<endl;
            }
        }
    }
    return 0;
}
